import { useEffect, useRef, useState } from "react";

import styles from "./TopDishes.module.css";

const TopDishes = () => {
  const ref = useRef();
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
        }
      },
      { threshold: 0.2 },
    );

    observer.observe(ref.current);

    return () => observer.disconnect();
  }, []);

  return (
    <section
      ref={ref}
      className={`${styles.topDishes} ${visible ? styles.visible : ""}`}
      id="menu"
    >
      <h2 className={styles.topDishesTitle}>Top dishes</h2>
      <ul className={styles.menu}>
        <li className={styles.card}>
          <img
            src="data:image/jpeg;base64,"
            alt="photo"
            className={styles.cardImage}
          />
          <div className={styles.cardContent}>
            <h3 className={styles.cardTitle}>Кебаб классический</h3>
            <p>Мясо, овощи, фирменный соус</p>
            <p className={styles.price}>120 грн</p>
          </div>
        </li>
        <li className={styles.card}>
          <img
            src="data:image/jpeg;base64,"
            alt="photo"
            className={styles.cardImage}
          />
          <div className={styles.cardContent}>
            <h3 className={styles.cardTitle}>Кебаб сырный</h3>
            <p>Мясо, овощи, фирменный соус , сыр</p>
            <p className={styles.price}>120 грн</p>
          </div>
        </li>
        <li className={styles.card}>
          <img
            src="data:image/jpeg;base64,"
            alt="photo"
            className={styles.cardImage}
          />
          <div className={styles.cardContent}>
            <h3 className={styles.cardTitle}>Кебаб дёнер</h3>
            <p>Мясо, овощи, фирменный соус</p>
            <p className={styles.price}>120 грн</p>
          </div>
        </li>
        <li className={styles.card}>
          <img
            src="data:image/jpeg;base64,"
            alt="photo"
            className={styles.cardImage}
          />
          <div className={styles.cardContent}>
            <h3 className={styles.cardTitle}>Шиш-кебаб</h3>
            <p>Мясо, овощи, фирменный соус</p>
            <p className={styles.price}>120 грн</p>
          </div>
        </li>
      </ul>
    </section>
  );
};

export default TopDishes;
